// src/App.js - DARK THEME WITH GLASS EFFECTS & DATE RANGE
import React, { useState, useEffect } from 'react';
import {
  Package,
  ShoppingCart,
  Receipt,
  TrendingUp,
  Droplet,
  Cookie,
  Wheat,
  Flame,
  Candy,
  Box,
  RefreshCw,
  Lock,
  LogOut,
  Users,
  Calendar,
  Phone,
  KeyRound,
  Filter,
  ArrowUpCircle,
  ArrowDownCircle,
} from 'lucide-react';
import {
  LineChart,
  Line,
  PieChart,
  Pie,
  Cell,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import axios from 'axios';
import './App.css';

// Backend API URL
// const API_BASE_URL = 'https://makhanchor-backend.onrender.com/api';

const API_BASE_URL = 'http://localhost:5000/api';

// Create axios instance
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Add token to requests
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('dashboard_token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Handle auth errors
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('dashboard_token');
      localStorage.removeItem('dashboard_user');
      window.location.reload();
    }
    return Promise.reject(error);
  }
);

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [mobile, setMobile] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [loginLoading, setLoginLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [dashboardData, setDashboardData] = useState(null);
  const [lastUpdated, setLastUpdated] = useState(null);
  const [userName, setUserName] = useState('');

  // Date range state
  const [dateRange, setDateRange] = useState('today');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [showDatePicker, setShowDatePicker] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('dashboard_token');
    const user = localStorage.getItem('dashboard_user');
    if (token && user) {
      setIsAuthenticated(true);
      setUserName(JSON.parse(user).name);
    }
  }, []);

  useEffect(() => {
    if (isAuthenticated) {
      fetchDashboardData();
      const interval = setInterval(fetchDashboardData, 5 * 60 * 1000);
      return () => clearInterval(interval);
    }
  }, [isAuthenticated, dateRange, startDate, endDate]);

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoginLoading(true);
    setLoginError('');

    try {
      const response = await axios.post(`${API_BASE_URL}/auth/login`, {
        mobile,
        password,
      });

      if (response.data.success) {
        localStorage.setItem('dashboard_token', response.data.token);
        localStorage.setItem('dashboard_user', JSON.stringify(response.data.data));
        setUserName(response.data.data.name);
        setIsAuthenticated(true);
      }
    } catch (error) {
      setLoginError(
        error.response?.data?.message || 'Invalid credentials. Please try again.'
      );
    } finally {
      setLoginLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('dashboard_token');
    localStorage.removeItem('dashboard_user');
    setIsAuthenticated(false);
    setMobile('');
    setPassword('');
    setDashboardData(null);
    setUserName('');
  };

  // COMPLETELY FIXED getDateRange function
// Replace the entire function in App.js (around line 116)

const getDateRange = () => {
  // Helper function to format date as YYYY-MM-DD without timezone issues
  const formatDate = (date) => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const now = new Date();
  let start, end;

  switch (dateRange) {
    case 'today':
      // Today only
      start = formatDate(now);
      end = formatDate(now);
      break;

    case 'yesterday':
      // Yesterday only
      const yesterday = new Date(now);
      yesterday.setDate(yesterday.getDate() - 1);
      start = formatDate(yesterday);
      end = formatDate(yesterday);
      break;

    case 'last7days':
      // Last 7 days including today
      const sevenDaysAgo = new Date(now);
      sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 6);
      start = formatDate(sevenDaysAgo);
      end = formatDate(now);
      break;

    case 'last30days':
      // Last 30 days including today
      const thirtyDaysAgo = new Date(now);
      thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 29);
      start = formatDate(thirtyDaysAgo);
      end = formatDate(now);
      break;

    case 'thisMonth':
      // From 1st of current month to today
      const firstDay = new Date(now.getFullYear(), now.getMonth(), 1);
      start = formatDate(firstDay);
      end = formatDate(now);
      break;

    case 'lastMonth':
      // Full previous month
      const firstDayLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      const lastDayLastMonth = new Date(now.getFullYear(), now.getMonth(), 0);
      start = formatDate(firstDayLastMonth);
      end = formatDate(lastDayLastMonth);
      break;

    case 'custom':
      if (startDate && endDate) {
        start = startDate; // Already in YYYY-MM-DD format
        end = endDate;     // Already in YYYY-MM-DD format
      } else {
        // Default to last 7 days
        const defaultStart = new Date(now);
        defaultStart.setDate(defaultStart.getDate() - 6);
        start = formatDate(defaultStart);
        end = formatDate(now);
      }
      break;

    default:
      // Default to today
      start = formatDate(now);
      end = formatDate(now);
  }

  console.log('Date Range Selected:', dateRange);
  console.log('Start Date:', start);
  console.log('End Date:', end);

  return { start, end };
};

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const dates = getDateRange();
      const params = {
        startDate: dates.start,
        endDate: dates.end,
      };

      // Fetch all data
      const [
        rangeProd,
        rangeSales,
        allTimeProd,
        allTimeSales,
        inventory,
        inventoryImports,
        inventoryConsumption,
        rawMaterials,
        miscStats,
        trendProdData,
        trendSalesData,
        customerSalesData,
      ] = await Promise.all([
        api.get(`/production/stats`, { params }),
        api.get(`/sales/stats`, { params }),
        api.get(`/production/stats`),
        api.get(`/sales/stats`),
        api.get(`/inventory/all/stats`),
        // Get imports in date range
        api.get(`/inventory/maida?type=import&startDate=${dates.start}&endDate=${dates.end}&limit=10000`),
        // Get consumption in date range
        api.get(`/inventory/maida?type=consumption&startDate=${dates.start}&endDate=${dates.end}&limit=10000`),
        api.get(`/raw-materials/stats/all`),
        api.get(`/miscellaneous/stats`, { params }),
        api.get(`/production`, { params: { ...params, limit: 1000 } }),
        api.get(`/sales`, { params: { ...params, limit: 1000 } }),
        api.get(`/sales`, { params: { ...params, limit: 1000 } }),
      ]);

      // Calculate inventory consumption for date range
      const calculateInventoryStats = async (category) => {
        const [imports, consumption] = await Promise.all([
          api.get(`/inventory/${category}?type=import&startDate=${dates.start}&endDate=${dates.end}&limit=10000`),
          api.get(`/inventory/${category}?type=consumption&startDate=${dates.start}&endDate=${dates.end}&limit=10000`),
        ]);

        const totalImported = imports.data.data.reduce((sum, item) => sum + item.quantity, 0);
        const totalConsumed = consumption.data.data.reduce((sum, item) => sum + item.quantity, 0);

        return { imported: totalImported, consumed: totalConsumed };
      };

      const [maidaStats, oilStats, gheeStats] = await Promise.all([
        calculateInventoryStats('maida'),
        calculateInventoryStats('oil'),
        calculateInventoryStats('ghee'),
      ]);

      // Calculate raw materials for date range
      const calculateRawMaterialPurchases = async (type) => {
        const response = await api.get(`/raw-materials/${type}?startDate=${dates.start}&endDate=${dates.end}&limit=10000`);
        if (type === 'gas') {
          const bigTanks = response.data.data.reduce((sum, item) => sum + (item.bigTanks || 0), 0);
          const smallTanks = response.data.data.reduce((sum, item) => sum + (item.smallTanks || 0), 0);
          return { bigTanks, smallTanks };
        }
        return response.data.data.reduce((sum, item) => sum + item.quantity, 0);
      };

      const [sujiPurchased, sugarPurchased, saltPurchased, gasPurchased] = await Promise.all([
        calculateRawMaterialPurchases('suji'),
        calculateRawMaterialPurchases('sugar'),
        calculateRawMaterialPurchases('salt'),
        calculateRawMaterialPurchases('gas'),
      ]);

      const trendData = processWeeklyTrend(
        trendProdData.data.data,
        trendSalesData.data.data
      );

      const topCustomers = processTopCustomers(customerSalesData.data.data);

      console.log("rangeProd", rangeProd);
      setDashboardData({
        range: {

          production: rangeProd.data.data.totalProduction || 0,
          sales: rangeSales.data.data.totalSales || 0,
          rem
        },
        allTime: {
          production: allTimeProd.data.data.totalProduction || 0,
          sales: allTimeSales.data.data.totalSales || 0,
          remaining: allTimeProd.data.data.totalRemaining || 0,
        },
        inventory: {
          maida: {
            currentStock: inventory.data.data.maida?.currentStock || 0,
            imported: maidaStats.imported,
            consumed: maidaStats.consumed,
          },
          oil: {
            currentStock: inventory.data.data.oil?.currentStock || 0,
            imported: oilStats.imported,
            consumed: oilStats.consumed,
          },
          ghee: {
            currentStock: inventory.data.data.ghee?.currentStock || 0,
            imported: gheeStats.imported,
            consumed: gheeStats.consumed,
          },
        },
        rawMaterials: {
          suji: sujiPurchased,
          sugar: sugarPurchased,
          salt: saltPurchased,
          gasBig: gasPurchased.bigTanks || 0,
          gasSmall: gasPurchased.smallTanks || 0,
        },
        miscellaneous: {
          totalSpending: miscStats.data.data.rangeSpending || miscStats.data.data.totalSpending || 0,
        },
        trendData,
        topCustomers,
      });

      setLastUpdated(new Date());
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      if (error.response?.status === 401) {
        alert('Session expired. Please login again.');
        handleLogout();
      } else {
        alert('Failed to load dashboard data');
      }
    } finally {
      setLoading(false);
    }
  };

  const processWeeklyTrend = (production, sales) => {
    const dailyData = {};

    production.forEach(p => {
      const date = p.date.split('T')[0];
      if (!dailyData[date]) {
        dailyData[date] = { date, production: 0, sales: 0 };
      }
      dailyData[date].production += p.packets;
    });

    sales.forEach(s => {
      const date = s.date.split('T')[0];
      if (!dailyData[date]) {
        dailyData[date] = { date, production: 0, sales: 0 };
      }
      dailyData[date].sales += s.packets;
    });

    return Object.values(dailyData)
      .sort((a, b) => new Date(a.date) - new Date(b.date))
      .map(d => ({
        date: new Date(d.date).toLocaleDateString('en-IN', { day: '2-digit', month: 'short' }),
        production: d.production,
        sales: d.sales,
      }));
  };

  const toTotalDabbas = (packetValue) => {
    const packets = Math.floor(packetValue);
    const dabbas = Math.round((packetValue - packets) * 100);
    return (packets * 16) + dabbas;
  };

  const processTopCustomers = (sales) => {
    const customerMap = {};

    sales.forEach(s => {
      const customer = s.customer || 'Walk-in';
      if (!customerMap[customer]) {
        customerMap[customer] = { name: customer, dabbas: 0, packets: 0 };
      }
      customerMap[customer].dabbas += toTotalDabbas(s.packets);
      customerMap[customer].packets = customerMap[customer].dabbas / 16;
    });

    return Object.values(customerMap)
      .sort((a, b) => b.dabbas - a.dabbas)
      .slice(0, 5);
  };

  const getDateRangeLabel = () => {
    const labels = {
      today: 'Today',
      yesterday: 'Yesterday',
      last7days: 'Last 7 Days',
      last30days: 'Last 30 Days',
      thisMonth: 'This Month',
      lastMonth: 'Last Month',
      custom: 'Custom Range',
    };
    return labels[dateRange] || 'Today';
  };

  // Login Screen
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4 bg-dark-gradient">
        <div className="glass-dark w-full max-w-md p-8 animate-slide-up">
          <div className="text-center mb-8">
            <div className="w-20 h-20 mx-auto mb-4 rounded-full bg-gradient-to-br from-orange-500 to-orange-700 flex items-center justify-center shadow-glow">
              <Lock className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-bold text-white mb-2">MakhanChor</h1>
            <p className="text-gray-400">Dashboard Login</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">
                Mobile Number
              </label>
              <div className="relative">
                <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={20} />
                <input
                  type="tel"
                  inputMode="numeric"
                  maxLength="10"
                  value={mobile}
                  onChange={(e) => {
                    setMobile(e.target.value);
                    setLoginError('');
                  }}
                  className="input-dark w-full pl-11"
                  placeholder="Enter mobile number"
                  required
                  autoFocus
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">
                Password
              </label>
              <div className="relative">
                <KeyRound className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={20} />
                <input
                  type="password"
                  value={password}
                  onChange={(e) => {
                    setPassword(e.target.value);
                    setLoginError('');
                  }}
                  className="input-dark w-full pl-11"
                  placeholder="Enter password"
                  required
                />
              </div>
              {loginError && (
                <p className="text-red-400 text-sm mt-2">{loginError}</p>
              )}
            </div>

            <button
              type="submit"
              disabled={loginLoading}
              className="btn-primary w-full"
            >
              {loginLoading ? 'Logging in...' : 'Login'}
            </button>
          </form>

          <div className="mt-6 text-center text-xs text-gray-500">
            Secured access for authorized personnel only
          </div>
        </div>
      </div>
    );
  }

  // Loading State
  if (loading && !dashboardData) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-dark-gradient">
        <div className="text-center">
          <RefreshCw className="animate-spin text-orange-500 mx-auto mb-4" size={48} />
          <p className="text-gray-400 text-lg">Loading dashboard...</p>
        </div>
      </div>
    );
  }

  if (!dashboardData) return null;

  const inventoryData = [
    { name: 'Maida', value: dashboardData.inventory.maida.currentStock, color: '#f59e0b' },
    { name: 'Oil', value: dashboardData.inventory.oil.currentStock, color: '#eab308' },
    { name: 'Ghee', value: dashboardData.inventory.ghee.currentStock, color: '#f97316' },
  ];

  return (
    <div className="min-h-screen bg-dark-gradient p-4 md:p-6">
      {/* Header */}
      <div className="glass-dark p-4 md:p-6 mb-6">
        <div className="flex items-center justify-between flex-wrap gap-4">
          <div>
            <h1 className="text-2xl md:text-3xl font-bold text-white mb-1">
              MakhanChor Dashboard
            </h1>
            <p className="text-sm text-gray-400">
              Welcome, {userName} • {lastUpdated && lastUpdated.toLocaleTimeString('en-IN')}
            </p>
          </div>
          <div className="flex gap-2">
            <button
              onClick={fetchDashboardData}
              disabled={loading}
              className="btn-icon"
              title="Refresh"
            >
              <RefreshCw className={`text-orange-400 ${loading ? 'animate-spin' : ''}`} size={20} />
            </button>
            <button
              onClick={handleLogout}
              className="btn-icon-danger"
              title="Logout"
            >
              <LogOut className="text-red-400" size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* Date Range Filter */}
      <div className="glass-dark p-4 mb-6">
        <div className="flex items-center gap-2 mb-3">
          <Filter size={18} className="text-orange-400" />
          <h3 className="font-semibold text-white">Date Range</h3>
        </div>
        <div className="flex flex-wrap gap-2">
          {[
            { value: 'today', label: 'Today' },
            { value: 'yesterday', label: 'Yesterday' },
            { value: 'last7days', label: 'Last 7 Days' },
            { value: 'last30days', label: 'Last 30 Days' },
            { value: 'thisMonth', label: 'This Month' },
            { value: 'lastMonth', label: 'Last Month' },
            { value: 'custom', label: 'Custom' },
          ].map(option => (
            <button
              key={option.value}
              onClick={() => {
                setDateRange(option.value);
                if (option.value === 'custom') {
                  setShowDatePicker(true);
                } else {
                  setShowDatePicker(false);
                }
              }}
              className={`px-4 py-2 rounded-lg font-medium text-sm transition-all ${
                dateRange === option.value
                  ? 'bg-gradient-to-r from-orange-500 to-orange-600 text-white shadow-glow'
                  : 'bg-white/5 text-gray-300 hover:bg-white/10 backdrop-blur-sm'
              }`}
            >
              {option.label}
            </button>
          ))}
        </div>

        {showDatePicker && dateRange === 'custom' && (
          <div className="flex gap-3 items-center mt-4 flex-wrap">
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="input-dark"
            />
            <span className="text-gray-500">to</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="input-dark"
            />
          </div>
        )}
      </div>

      {/* Stats Cards - Production & Sales Only */}
      <div className="mb-6">
        <h2 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
          <Calendar size={20} className="text-orange-400" />
          {getDateRangeLabel()} Summary
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <StatCard
            icon={Package}
            title="Production"
            value={dashboardData.range.production}
            subtitle="packets"
            color="blue"
          />
          <StatCard
            icon={ShoppingCart}
            title="Sales"
            value={dashboardData.range.sales}
            subtitle="packets"
            color="green"
          />
          <StatCard
            icon={ShoppingCart}
            title="Stocks Remaining"
            value={dashboardData.range.remaining}
            subtitle="packets"
            color="green"
          />
        </div>
      </div>

      {/* Miscellaneous as Info Point */}
      <div className="glass-dark p-4 mb-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-purple-500/20 flex items-center justify-center">
              <Receipt className="text-purple-400" size={20} />
            </div>
            <div>
              <p className="text-sm text-gray-400">Miscellaneous Spending</p>
              <p className="text-2xl font-bold text-white">
                ₹{dashboardData.miscellaneous.totalSpending.toLocaleString('en-IN')}
              </p>
            </div>
          </div>
          {/* <div className="text-xs text-gray-500">{getDateRangeLabel()}</div> */}
          <div className="text-xs text-gray-500">Total</div>
        </div>
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        {/* Trend Chart */}
        <div className="glass-dark p-4 md:p-6">
          <h3 className="text-lg font-semibold text-white mb-4">Production vs Sales Trend</h3>
          <ResponsiveContainer width="100%" height={250}>
            <LineChart data={dashboardData.trendData}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.1)" />
              <XAxis dataKey="date" tick={{ fill: '#9ca3af', fontSize: 12 }} />
              <YAxis tick={{ fill: '#9ca3af', fontSize: 12 }} />
              <Tooltip
                contentStyle={{
                  backgroundColor: 'rgba(17, 24, 39, 0.95)',
                  border: '1px solid rgba(255,255,255,0.1)',
                  borderRadius: '12px',
                  backdropFilter: 'blur(10px)',
                }}
              />
              <Legend />
              <Line
                type="monotone"
                dataKey="production"
                stroke="#3b82f6"
                strokeWidth={3}
                name="Production"
                dot={{ r: 4 }}
              />
              <Line
                type="monotone"
                dataKey="sales"
                stroke="#10b981"
                strokeWidth={3}
                name="Sales"
                dot={{ r: 4 }}
              />
            </LineChart>
          </ResponsiveContainer>
        </div>

        {/* Inventory Pie */}
        <div className="glass-dark p-4 md:p-6">
          <h3 className="text-lg font-semibold text-white mb-4">Current Stock</h3>
          <ResponsiveContainer width="100%" height={250}>
            <PieChart>
              <Pie
                data={inventoryData}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ name, value }) => `${name}: ${value}`}
                outerRadius={80}
                fill="#8884d8"
                dataKey="value"
              >
                {inventoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip
                contentStyle={{
                  backgroundColor: 'rgba(17, 24, 39, 0.95)',
                  border: '1px solid rgba(255,255,255,0.1)',
                  borderRadius: '12px',
                }}
              />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Inventory Details with Usage */}
      <div className="glass-dark p-4 md:p-6 mb-6">
        <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
          <Box size={20} className="text-orange-400" />
          Inventory Details ({getDateRangeLabel()})
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <InventoryCard
            icon={Wheat}
            name="Maida"
            currentStock={dashboardData.inventory.maida.currentStock}
            imported={dashboardData.inventory.maida.imported}
            consumed={dashboardData.inventory.maida.consumed}
            unit="packets"
            color="amber"
          />
          <InventoryCard
            icon={Droplet}
            name="Oil"
            currentStock={dashboardData.inventory.oil.currentStock}
            imported={dashboardData.inventory.oil.imported}
            consumed={dashboardData.inventory.oil.consumed}
            unit="tins"
            color="yellow"
          />
          <InventoryCard
            icon={Cookie}
            name="Ghee"
            currentStock={dashboardData.inventory.ghee.currentStock}
            imported={dashboardData.inventory.ghee.imported}
            consumed={dashboardData.inventory.ghee.consumed}
            unit="dabba"
            color="orange"
          />
        </div>
      </div>

      {/* Bottom Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Raw Materials */}
        <div className="glass-dark p-4 md:p-6">
          <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
            <Box size={20} className="text-orange-400" />
            Raw Materials Purchased ({getDateRangeLabel()})
          </h3>
          <div className="space-y-3">
            <MaterialRow
              icon={Wheat}
              name="Suji"
              value={dashboardData.rawMaterials.suji}
              unit="packets"
              color="yellow"
            />
            <MaterialRow
              icon={Candy}
              name="Sugar"
              value={dashboardData.rawMaterials.sugar}
              unit="packets"
              color="pink"
            />
            <MaterialRow
              icon={Box}
              name="Salt"
              value={dashboardData.rawMaterials.salt}
              unit="packets"
              color="gray"
            />
            <MaterialRow
              icon={Flame}
              name="Gas (Big)"
              value={dashboardData.rawMaterials.gasBig}
              unit="tanks"
              color="red"
            />
            <MaterialRow
              icon={Flame}
              name="Gas (Small)"
              value={dashboardData.rawMaterials.gasSmall}
              unit="tanks"
              color="orange"
            />
          </div>
        </div>

        {/* Top Customers */}
        <div className="glass-dark p-4 md:p-6">
          <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
            <Users size={20} className="text-green-400" />
            Top Customers ({getDateRangeLabel()})
          </h3>
          {dashboardData.topCustomers.length === 0 ? (
            <p className="text-center text-gray-500 py-8">No data available</p>
          ) : (
            <div className="space-y-3">
              {dashboardData.topCustomers.map((customer, index) => (
                <div key={index} className="flex items-center gap-3">
                  <div className="flex-shrink-0 w-10 h-10 rounded-full bg-gradient-to-br from-green-400 to-green-600 flex items-center justify-center text-white font-bold shadow-glow">
                    {index + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-semibold text-white truncate">
                        {customer.name}
                      </span>
                      <span className="text-sm font-bold text-green-400 ml-2">
                        {customer.packets.toFixed(1)}
                      </span>
                    </div>
                    <div className="w-full bg-white/10 rounded-full h-2 overflow-hidden backdrop-blur-sm">
                      <div
                        className="bg-gradient-to-r from-green-400 to-green-600 h-full rounded-full"
                        style={{
                          width: `${(customer.dabbas / dashboardData.topCustomers[0].dabbas) * 100}%`,
                        }}
                      ></div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Overall Stats */}
      <div className="mt-6 glass-dark p-4 md:p-6">
        <h3 className="text-lg font-semibold text-white mb-4">Overall Statistics (All Time)</h3>
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          <div className="text-center">
            <div className="text-3xl font-bold text-blue-400">
              {dashboardData.allTime.production}
            </div>
            <div className="text-sm text-gray-400 mt-1">Total Production</div>
          </div>
          <div className="text-center">
            <div className="text-3xl font-bold text-green-400">
              {dashboardData.allTime.sales}
            </div>
            <div className="text-sm text-gray-400 mt-1">Total Sales</div>
          </div>
          <div className="text-center">
            <div className="text-3xl font-bold text-orange-400">
              {dashboardData.allTime.remaining}
            </div>
            <div className="text-sm text-gray-400 mt-1">Stock Remaining</div>
          </div>
        </div>
      </div>
    </div>
  );
};

// Stat Card Component
const StatCard = ({ icon: Icon, title, value, subtitle, color }) => {
  const colorClasses = {
    blue: { gradient: 'from-blue-500 to-blue-700', bg: 'bg-blue-500/20', text: 'text-blue-400' },
    green: { gradient: 'from-green-500 to-green-700', bg: 'bg-green-500/20', text: 'text-green-400' },
    purple: { gradient: 'from-purple-500 to-purple-700', bg: 'bg-purple-500/20', text: 'text-purple-400' },
    orange: { gradient: 'from-orange-500 to-orange-700', bg: 'bg-orange-500/20', text: 'text-orange-400' },
  };

  const colors = colorClasses[color];

  return (
    <div className="glass-dark p-6">
      <div className="flex items-center justify-between mb-3">
        <div className={`w-12 h-12 rounded-full ${colors.bg} flex items-center justify-center`}>
          <Icon className={colors.text} size={24} />
        </div>
        <span className="text-xs font-medium text-gray-400 uppercase">{title}</span>
      </div>
      <div className="text-4xl font-bold text-white mb-1">
        {value}
      </div>
      <div className="text-sm text-gray-400">{subtitle}</div>
    </div>
  );
};

// Inventory Card with Usage
const InventoryCard = ({ icon: Icon, name, currentStock, imported, consumed, unit, color }) => {
  const colorClasses = {
    amber: 'text-amber-400',
    yellow: 'text-yellow-400',
    orange: 'text-orange-400',
  };

  return (
    <div className="bg-white/5 backdrop-blur-sm rounded-xl p-4 border border-white/10">
      <div className="flex items-center gap-3 mb-3">
        <Icon className={colorClasses[color]} size={24} />
        <span className="font-semibold text-white">{name}</span>
      </div>
      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <span className="text-sm text-gray-400">Current Stock:</span>
          <span className="font-bold text-white">{currentStock} {unit}</span>
        </div>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-1">
            <ArrowUpCircle className="text-green-400" size={14} />
            <span className="text-xs text-gray-400">Imported:</span>
          </div>
          <span className="text-sm text-green-400">{imported} {unit}</span>
        </div>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-1">
            <ArrowDownCircle className="text-red-400" size={14} />
            <span className="text-xs text-gray-400">Consumed:</span>
          </div>
          <span className="text-sm text-red-400">{consumed} {unit}</span>
        </div>
      </div>
    </div>
  );
};

// Material Row Component
const MaterialRow = ({ icon: Icon, name, value, unit, color }) => {
  const colorClasses = {
    yellow: 'text-yellow-400',
    pink: 'text-pink-400',
    gray: 'text-gray-400',
    red: 'text-red-400',
    orange: 'text-orange-400',
  };

  return (
    <div className="flex items-center justify-between p-3 rounded-xl bg-white/5 backdrop-blur-sm border border-white/10">
      <div className="flex items-center gap-3">
        <Icon className={colorClasses[color]} size={20} />
        <span className="font-medium text-white">{name}</span>
      </div>
      <div className="text-right">
        <div className="font-bold text-white">{value}</div>
        <div className="text-xs text-gray-400">{unit}</div>
      </div>
    </div>
  );
};

export default App;
